const raw = items.map((it) => it.json || it);

function pick(o, keys) {
  for (const k of keys) if (o[k] !== undefined && o[k] !== null) return o[k];
  return undefined;
}

function isOriginal(p) {
  const url = (pick(p, ['url', 'postUrl', 'link', 'permalink']) || '').toString().toLowerCase();
  if (!url.includes('/posts/alecfoster_')) return false;
  return true;
}

function normalize(p) {
  const text = pick(p, ['text', 'content', 'postContent', 'description']) || '';
  const url = pick(p, ['url', 'postUrl', 'link', 'permalink']) || '';
  const posted_at = pick(p, ['postedAt', 'postedAtIso', 'publishedAt', 'datePublished', 'postedAtTimestamp']);
  const likes = pick(p, ['totalReactionCount', 'numLikes', 'likesCount', 'likes', 'reactionsCount']) || 0;
  const comments = pick(p, ['commentsCount', 'numComments', 'comments']) || 0;
  const image_url = pick(p, ['imageUrl', 'thumbnail', 'image']) || null;
  const type = pick(p, ['postType', 'type']) || 'post';
  let iso = '';
  if (typeof posted_at === 'number') iso = new Date(posted_at).toISOString();
  else if (typeof posted_at === 'string') iso = new Date(posted_at).toISOString();
  return { url, text, posted_at: iso, likes: Number(likes), comments: Number(comments), image_url, type };
}

const posts = raw
  .filter(isOriginal)
  .map(normalize)
  .filter((p) => p.url && p.text)
  .sort((a, b) => new Date(b.posted_at) - new Date(a.posted_at))
  .slice(0, 5);

const payload = {
  updated_at: new Date().toISOString(),
  source: 'apify/supreme_coder/linkedin-post via n8n weekly cron',
  profile_url: 'https://www.linkedin.com/in/alecfoster',
  posts,
};

const json_text = JSON.stringify(payload, null, 2) + '\n';
const content_b64 = Buffer.from(json_text, 'utf-8').toString('base64');

return [{ json: { json_text, content_b64, post_count: posts.length } }];
